/// @brief Minimum expected trigger data payload size in bytes for field extraction.
/// @details Covers: dataUploadRequestFlg (1) + dataTransmissionNum (1) +
///          categoryIdentifier (4) + logDataStartTime (4) + logDataEndTime (4) = 14 bytes.
static constexpr std::size_t kMinTriggerPayloadSize{14U};

/// @brief Byte offset for the data upload request flag within the trigger payload.
static constexpr std::size_t kOffsetDataUploadRequestFlg{0U};

/// @brief Byte offset for the data transmission number within the trigger payload.
static constexpr std::size_t kOffsetDataTransmissionNum{1U};

/// @brief Byte offset for the category identifier (4 bytes, little-endian) within the trigger payload.
static constexpr std::size_t kOffsetCategoryIdentifier{2U};

/// @brief Byte offset for the log data start time (4 bytes, little-endian, signed) within the trigger payload.
static constexpr std::size_t kOffsetLogDataStartTime{6U};

/// @brief Byte offset for the log data end time (4 bytes, little-endian, signed) within the trigger payload.
static constexpr std::size_t kOffsetLogDataEndTime{10U};

/// @brief Default configured past data retention limit in seconds.
static constexpr uint32_t kDefaultRetentionLimit{10U};

/// @brief GEDR-only upload request flag value.
static constexpr uint8_t kGedrOnlyFlag{2U};

/**
 * @brief Extracts the data upload request flag from the trigger payload.
 * @details Reads a single uint8_t at the designated offset.
 * @param[in] triggerData Raw trigger data bytes. Must have size >= kMinTriggerPayloadSize.
 * @return Extracted data upload request flag value.
 * @throws None
 * @pre triggerData.size() >= kMinTriggerPayloadSize.
 * @post No state change.
 * @note Internal helper function.
 */
static uint8_t ExtractDataUploadRequestFlag(const std::vector<uint8_t>& triggerData) noexcept
{
    return triggerData[kOffsetDataUploadRequestFlg];
}

/**
 * @brief Extracts the data transmission number from the trigger payload.
 * @details Reads a single uint8_t at the designated offset.
 * @param[in] triggerData Raw trigger data bytes. Must have size >= kMinTriggerPayloadSize.
 * @return Extracted data transmission number value.
 * @throws None
 * @pre triggerData.size() >= kMinTriggerPayloadSize.
 * @post No state change.
 * @note Internal helper function.
 */
static uint8_t ExtractDataTransmissionNum(const std::vector<uint8_t>& triggerData) noexcept
{
    return triggerData[kOffsetDataTransmissionNum];
}

/**
 * @brief Extracts the category identifier (uint32_t, little-endian) from the trigger payload.
 * @details Reads 4 bytes starting at the designated offset and assembles them in little-endian order.
 * @param[in] triggerData Raw trigger data bytes. Must have size >= kMinTriggerPayloadSize.
 * @return Extracted category identifier value.
 * @throws None
 * @pre triggerData.size() >= kMinTriggerPayloadSize.
 * @post No state change.
 * @note Internal helper function.
 */
static uint32_t ExtractCategoryIdentifier(const std::vector<uint8_t>& triggerData) noexcept
{
    const uint32_t byte0 = static_cast<uint32_t>(triggerData[kOffsetCategoryIdentifier]);
    const uint32_t byte1 = static_cast<uint32_t>(triggerData[kOffsetCategoryIdentifier + 1U]);
    const uint32_t byte2 = static_cast<uint32_t>(triggerData[kOffsetCategoryIdentifier + 2U]);
    const uint32_t byte3 = static_cast<uint32_t>(triggerData[kOffsetCategoryIdentifier + 3U]);
    return (byte3 << 24U) | (byte2 << 16U) | (byte1 << 8U) | byte0;
}

/**
 * @brief Extracts the log data start time (int32_t, little-endian) from the trigger payload.
 * @details Reads 4 bytes starting at the designated offset and assembles them in little-endian order.
 * @param[in] triggerData Raw trigger data bytes. Must have size >= kMinTriggerPayloadSize.
 * @return Extracted log data start time value.
 * @throws None
 * @pre triggerData.size() >= kMinTriggerPayloadSize.
 * @post No state change.
 * @note Internal helper function.
 */
static int32_t ExtractLogDataStartTime(const std::vector<uint8_t>& triggerData) noexcept
{
    const uint32_t byte0 = static_cast<uint32_t>(triggerData[kOffsetLogDataStartTime]);
    const uint32_t byte1 = static_cast<uint32_t>(triggerData[kOffsetLogDataStartTime + 1U]);
    const uint32_t byte2 = static_cast<uint32_t>(triggerData[kOffsetLogDataStartTime + 2U]);
    const uint32_t byte3 = static_cast<uint32_t>(triggerData[kOffsetLogDataStartTime + 3U]);
    const uint32_t raw = (byte3 << 24U) | (byte2 << 16U) | (byte1 << 8U) | byte0;
    return static_cast<int32_t>(raw);
}

/**
 * @brief Extracts the log data end time (int32_t, little-endian) from the trigger payload.
 * @details Reads 4 bytes starting at the designated offset and assembles them in little-endian order.
 * @param[in] triggerData Raw trigger data bytes. Must have size >= kMinTriggerPayloadSize.
 * @return Extracted log data end time value.
 * @throws None
 * @pre triggerData.size() >= kMinTriggerPayloadSize.
 * @post No state change.
 * @note Internal helper function.
 */
static int32_t ExtractLogDataEndTime(const std::vector<uint8_t>& triggerData) noexcept
{
    const uint32_t byte0 = static_cast<uint32_t>(triggerData[kOffsetLogDataEndTime]);
    const uint32_t byte1 = static_cast<uint32_t>(triggerData[kOffsetLogDataEndTime + 1U]);
    const uint32_t byte2 = static_cast<uint32_t>(triggerData[kOffsetLogDataEndTime + 2U]);
    const uint32_t byte3 = static_cast<uint32_t>(triggerData[kOffsetLogDataEndTime + 3U]);
    const uint32_t raw = (byte3 << 24U) | (byte2 << 16U) | (byte1 << 8U) | byte0;
    return static_cast<int32_t>(raw);
}

/**
 * @brief Returns the configured past data retention limit.
 * @details Returns the default retention limit of 10 seconds.
 * @return Configured retention limit in seconds.
 * @throws None
 * @pre None.
 * @post No state change.
 * @note Internal helper function.
 */
static uint32_t GetConfiguredRetentionLimit() noexcept
{
    return kDefaultRetentionLimit;
}

