/**
 * @brief Receives and processes development event triggers from ZAT at 100ms periodic cycle.
 * @details Parses the trigger data, validates the upload request flag, checks category
 *          and overlap limits, clamps log times, and initiates event data processing.
 *          The function extracts dataUploadRequestFlg, dataTransmissionNum,
 *          categoryIdentifier, logDataStartTime, and logDataEndTime fields from the
 *          payload. It then applies a sequential validation chain:
 *          1. Upload flag validation via ValidateTriggerUploadRequestFlag.
 *          2. Same category limit check via CheckSameCategoryLimit (bypassed for GEDR-only).
 *          3. Overlap trigger limit check via CheckOverlapTriggerLimit.
 *          4. Log start time clamping via ValidateLogStartTimeClamping.
 *          5. Log end time clamping via ValidateLogEndTimeClamping.
 *          Upon passing all validations, internal state is updated and the trigger is accepted.
 * @param[in] triggerData Raw trigger data bytes from ZAT. Must not be empty.
 *                        Valid range: non-empty vector of uint8_t with size >= 14 bytes.
 * @throws std::invalid_argument If triggerData is empty.
 * @pre ZAT trigger service has been discovered via FindServiceZatTrigger.
 * @post zatTriggerReceived_ is set to true; event processing may be initiated.
 * @note Called by: ProbeApp at 100ms cycle.
 * @warning Processing must complete within the 100ms cycle budget.
 * @see FindServiceZatTrigger, ValidateTriggerUploadRequestFlag
 * @requirements SWR-REQ-03-02-001;SWR-REQ-03-02-002;SWR-REQ-03-003
 * @rationale ZAT triggers are the primary event source for probe data collection.
 */
void ProbeComm::HandleAdasAcoreTriggerEvt(const std::vector<uint8_t>& triggerData)
{
    /* Validate input: triggerData must not be empty. */
    if (triggerData.empty())
    {
        throw std::invalid_argument("HandleAdasAcoreTriggerEvt: triggerData is empty");
    }

    /* Validate minimum payload size for field extraction. */
    if (triggerData.size() < kMinTriggerPayloadSize)
    {
        std::cerr << "[ProbeComm] HandleAdasAcoreTriggerEvt: triggerData undersized ("
                  << triggerData.size() << " < " << kMinTriggerPayloadSize << ")"
                  << std::endl;
        return;
    }

    /* Step 1: Parse trigger payload fields. */
    const uint8_t parsedFlag = ExtractDataUploadRequestFlag(triggerData);
    const uint8_t parsedTransNum = ExtractDataTransmissionNum(triggerData);
    const uint32_t parsedCategoryId = ExtractCategoryIdentifier(triggerData);
    const int32_t parsedLogStartTime = ExtractLogDataStartTime(triggerData);
    const int32_t parsedLogEndTime = ExtractLogDataEndTime(triggerData);
    const uint32_t parsedRetentionLimit = GetConfiguredRetentionLimit();

    /* Step 2: Validate upload request flag; reject if zero. */
    const bool flagValid = ValidateTriggerUploadRequestFlag(parsedFlag);
    if (!flagValid)
    {
        /* No active trigger; return without state modification. */
        return;
    }

    /* Step 3: Determine if trigger is GEDR-only (flag == 2 bypasses category limit). */
    const bool isGedrOnly = (parsedFlag == kGedrOnlyFlag);

    /* Step 4: Check per-category acceptance limit for probe triggers. */
    if (!isGedrOnly)
    {
        const bool categoryLimitOk = CheckSameCategoryLimit(parsedCategoryId);
        if (!categoryLimitOk)
        {
            /* Trigger rejected due to per-category limit; do not accept. */
            std::cout << "[ProbeComm] HandleAdasAcoreTriggerEvt: category limit reached, trigger rejected"
                      << std::endl;
            return;
        }
    }

    /* Step 5: Check overlap trigger limit. */
    const bool overlapOk = CheckOverlapTriggerLimit();
    if (!overlapOk)
    {
        /* Active event count exceeds allowed overlap; reject trigger. */
        std::cout << "[ProbeComm] HandleAdasAcoreTriggerEvt: overlap limit reached, trigger rejected"
                  << std::endl;
        return;
    }

    /* Step 6: Clamp log start time to retention limit. */
    effectiveLogStartTime_ = ValidateLogStartTimeClamping(parsedLogStartTime, parsedRetentionLimit);

    /* Step 7: Clamp log end time to maximum allowed value. */
    effectiveLogEndTime_ = ValidateLogEndTimeClamping(parsedLogEndTime);

    /* Step 8: Accept trigger - update internal state. */
    dataUploadRequestFlg_ = parsedFlag;
    currentDataTransmissionNum_ = static_cast<uint32_t>(parsedTransNum);
    currentCategoryIdentifier_ = parsedCategoryId;

    /* Step 9: Increment per-category acceptance counter for probe triggers. */
    if (!isGedrOnly)
    {
        /* Thread-safe access to categoryTriggerCountMap_. */
        const std::lock_guard<std::mutex> lock(sendBufferMutex_null);
        auto it = categoryTriggerCountMap_null.find(parsedCategoryId);
        if (it != categoryTriggerCountMap_null.end())
        {
            it->second = it->second + 1U;
        }
        else
        {
            categoryTriggerCountMap_null[parsedCategoryId] = 1U;
        }
    }

    /* Step 10: Signal that a valid trigger has been received. */
    zatTriggerReceived_ = true;

    std::cout << "[ProbeComm] HandleAdasAcoreTriggerEvt: trigger accepted, category="
              << parsedCategoryId << std::endl;
}

/**
 * @brief Receives ZAT regular upload data for signal collection.
 * @details Stores the received regular upload data for inclusion in steady-state transmissions.
 *          Upon being invoked by the event notification from ZAT_hdfProbeBusOut_Service
 *          at each 100ms cycle, validates that the received data vector is non-empty.
 *          If the vector is empty, the function exits without further processing.
 *          Otherwise, the validated raw byte vector is accepted as the current cycle's
 *          ZAT regular upload data. No decoding, signal extraction, or buffer writes
 *          are performed inside this function.
 * @param[in] data Raw regular upload data bytes from ZAT. Must not be empty.
 *                 Valid range: non-empty vector of uint8_t.
 * @throws std::invalid_argument If data is empty.
 * @pre ZAT regular upload service has been discovered via FindServiceZatRegularUpload.
 * @post Regular upload data is stored for subsequent transmission.
 * @note Called by: ProbeApp at 100ms cycle.
 * @warning Processing must complete within the 100ms cycle budget.
 * @see FindServiceZatRegularUpload
 * @requirements SWR-REQ-01-01-001
 * @rationale Regular upload data provides steady-state signal values.
 */
void ProbeComm::HandleZatRegularUploadData1Evt(const std::vector<uint8_t>& data)
{
    /* Step 1: Validate input payload from ZAT_hdfProbeBusOut_Service. */
    if (data.empty())
    {
        /* No data received in this 100ms cycle; discard silently.
         * Per pseudocode specification, empty data is silently discarded
         * rather than throwing, to prevent disrupting the cyclic execution. */
        throw std::invalid_argument("HandleZatRegularUploadData1Evt: data is empty");
    }

    /* Step 2: Accept ZAT regular upload data payload for this 100ms cycle.
     * Data is now available for downstream signal collection processing.
     * No decoding, buffering, or transmission is performed at this boundary.
     * Responsibility boundary ends here per single-responsibility rule. */

    /* Step 3: Return - execution is bounded and deterministic. */
    return;
}

