/// @brief Byte offset of the acceptance status field within the CameraHost answer back payload.
/// @details Defined per CameraHost_IMG_Service interface specification.
static constexpr std::size_t kAnswerBackAcceptanceOffset{0U};

/// @brief Byte offset of the trigger error code high byte within the answer back payload.
/// @details Two consecutive bytes starting at this offset form the 16-bit trigger error code.
static constexpr std::size_t kTriggerErrorCodeOffset{1U};

/// @brief Minimum required size of the answer back payload in bytes.
/// @details Must contain at least the acceptance byte and 2-byte error code.
static constexpr std::size_t kMinAnswerBackPayloadSize{3U};

/// @brief Byte offset of the PictureSize field (uint16_t, little-endian) within the image payload.
static constexpr std::size_t kPictureSizeOffset{0U};

/// @brief Byte offset of the timestamp seconds field (uint32_t, little-endian) within the image payload.
static constexpr std::size_t kTimestampSecOffset{2U};

/// @brief Byte offset of the timestamp milliseconds field (uint32_t, little-endian) within the image payload.
static constexpr std::size_t kTimestampMsecOffset{6U};

/// @brief Byte offset of the frame counter field (uint16_t, little-endian) within the image payload.
static constexpr std::size_t kFrameCounterOffset{10U};

/// @brief Minimum required size of the image payload header in bytes.
/// @details Must contain PictureSize(2) + TimestampSec(4) + TimestampMsec(4) + FrameCounter(2) = 12 bytes minimum.
static constexpr std::size_t kMinImagePayloadHeaderSize{12U};

/// @brief Total number of expected camera images in the acquisition sequence.
/// @details Covers the -5 to +8 second window around the event at 1-second intervals.
static constexpr uint16_t kExpectedImageCount{14U};

/// @brief Maximum acceptable size in bytes for an event signal payload.
/// @details Payloads exceeding this value are discarded to prevent buffer overrun.
static constexpr std::size_t kMaxEventSignalPayloadSize{65535U};

/* ===================================================================
 * Internal Helper Functions
 * =================================================================== */

/**
 * @brief Extracts the trigger-stage error code from the answer back payload.
 * @details Reads two bytes at kTriggerErrorCodeOffset in little-endian order
 *          and combines them into a uint16_t error code value.
 * @param[in] answerData Raw answer back payload from CameraHost. Must have
 *                       size >= kMinAnswerBackPayloadSize.
 * @return Extracted 16-bit trigger error code.
 * @pre answerData.size() >= kMinAnswerBackPayloadSize.
 * @post No state change.
 * @note Internal helper — not part of the public API.
 */
static uint16_t ExtractTriggerErrorCode(const std::vector<uint8_t>& answerData) noexcept
{
    const uint16_t lowByte  = static_cast<uint16_t>(answerData[kTriggerErrorCodeOffset]);
    const uint16_t highByte = static_cast<uint16_t>(answerData[kTriggerErrorCodeOffset + 1U]);
    return static_cast<uint16_t>(lowByte | static_cast<uint16_t>(highByte << 8U));
}

/**
 * @brief Extracts the PictureSize field from the image data payload.
 * @details Reads two bytes at kPictureSizeOffset in little-endian order.
 * @param[in] imageData Raw image data payload from CameraHost. Must have
 *                      size >= kMinImagePayloadHeaderSize.
 * @return Extracted 16-bit picture size value.
 * @pre imageData.size() >= kMinImagePayloadHeaderSize.
 * @post No state change.
 * @note Internal helper — not part of the public API.
 */
static uint16_t ExtractPictureSize(const std::vector<uint8_t>& imageData) noexcept
{
    const uint16_t lowByte  = static_cast<uint16_t>(imageData[kPictureSizeOffset]);
    const uint16_t highByte = static_cast<uint16_t>(imageData[kPictureSizeOffset + 1U]);
    return static_cast<uint16_t>(lowByte | static_cast<uint16_t>(highByte << 8U));
}

/**
 * @brief Extracts the seconds component of the timestamp from the image data payload.
 * @details Reads four bytes at kTimestampSecOffset in little-endian order.
 * @param[in] imageData Raw image data payload from CameraHost. Must have
 *                      size >= kMinImagePayloadHeaderSize.
 * @return Extracted 32-bit timestamp seconds value.
 * @pre imageData.size() >= kMinImagePayloadHeaderSize.
 * @post No state change.
 * @note Internal helper — not part of the public API.
 */
static uint32_t ExtractTimestampSec(const std::vector<uint8_t>& imageData) noexcept
{
    const uint32_t byte0 = static_cast<uint32_t>(imageData[kTimestampSecOffset]);
    const uint32_t byte1 = static_cast<uint32_t>(imageData[kTimestampSecOffset + 1U]);
    const uint32_t byte2 = static_cast<uint32_t>(imageData[kTimestampSecOffset + 2U]);
    const uint32_t byte3 = static_cast<uint32_t>(imageData[kTimestampSecOffset + 3U]);
    return (byte0 | (byte1 << 8U) | (byte2 << 16U) | (byte3 << 24U));
}

/**
 * @brief Extracts the milliseconds component of the timestamp from the image data payload.
 * @details Reads four bytes at kTimestampMsecOffset in little-endian order.
 * @param[in] imageData Raw image data payload from CameraHost. Must have
 *                      size >= kMinImagePayloadHeaderSize.
 * @return Extracted 32-bit timestamp milliseconds value.
 * @pre imageData.size() >= kMinImagePayloadHeaderSize.
 * @post No state change.
 * @note Internal helper — not part of the public API.
 */
static uint32_t ExtractTimestampMsec(const std::vector<uint8_t>& imageData) noexcept
{
    const uint32_t byte0 = static_cast<uint32_t>(imageData[kTimestampMsecOffset]);
    const uint32_t byte1 = static_cast<uint32_t>(imageData[kTimestampMsecOffset + 1U]);
    const uint32_t byte2 = static_cast<uint32_t>(imageData[kTimestampMsecOffset + 2U]);
    const uint32_t byte3 = static_cast<uint32_t>(imageData[kTimestampMsecOffset + 3U]);
    return (byte0 | (byte1 << 8U) | (byte2 << 16U) | (byte3 << 24U));
}

/**
 * @brief Extracts the frame counter field from the image data payload.
 * @details Reads two bytes at kFrameCounterOffset in little-endian order
 *          and returns the value as uint16_t.
 * @param[in] imageData Raw image data payload from CameraHost. Must have
 *                      size >= kMinImagePayloadHeaderSize.
 * @return Extracted 16-bit frame counter value.
 * @pre imageData.size() >= kMinImagePayloadHeaderSize.
 * @post No state change.
 * @note Internal helper — not part of the public API.
 */
static uint16_t ExtractFrameCounter(const std::vector<uint8_t>& imageData) noexcept
{
    const uint16_t lowByte  = static_cast<uint16_t>(imageData[kFrameCounterOffset]);
    const uint16_t highByte = static_cast<uint16_t>(imageData[kFrameCounterOffset + 1U]);
    return static_cast<uint16_t>(lowByte | static_cast<uint16_t>(highByte << 8U));
}

