/**
 * @brief Receives and processes the BDP upload completion result code from DAQ.
 * @details Evaluates the resultCode against the known success indicator value.
 *          If the result code indicates successful acceptance by DAQ, the function
 *          calls DeleteEventDataAfterDaqSuccess to purge the development event data
 *          associated with this transmission from the active process memory. If the
 *          result code does not indicate success, no deletion is performed and no
 *          retry is initiated within this function; retry logic is managed separately
 *          by the BDP transmit retry path. The function is deterministic, bounded in
 *          execution, and performs no blocking operations.
 * @param[in] resultCode BDP upload result code from DAQ. Valid range: [0, 65535].
 *                       Value 0x0000 indicates success.
 * @pre BDP data has been transmitted to DAQ via TransmitBdpDataToDAQ.
 * @post Event data may be deleted on success, or state is preserved for retry handling.
 * @note Called by: ProbeApp on event trigger.
 * @warning Does not implement retry logic; retry and abort paths are handled externally
 *          by EnforceBdpTransmitRetry and AbortEventDataTransmissionOnRetryExhaustion.
 * @see DeleteEventDataAfterDaqSuccess, AbortEventDataTransmissionOnRetryExhaustion
 * @requirements SWR-REQ-03-10-001
 * @rationale DAQ result code determines the lifecycle of event data in memory.
 *           Only confirmed success triggers memory release to prevent premature deletion.
 */
void ProbeComm::HandleResultBdpEvt(const uint16_t resultCode)
{
    /* Step 1: Validate the received result code against known success indicator */
    if (resultCode == kBdpResultCodeSuccess)
    {
        /* Step 2: Invoke memory cleanup for the confirmed-successful event data */
        DeleteEventDataAfterDaqSuccess();
    }
    else
    {
        /* Step 3: No action on non-success; retry and abort paths handled externally.
         * State is preserved for retry handling by EnforceBdpTransmitRetry
         * and AbortEventDataTransmissionOnRetryExhaustion. */
    }

    /* Step 4: Function returns; no further state change within this unit */
}

/**
 * @brief Checks if the data upload request flag is non-zero to determine valid trigger.
 * @details Evaluates whether the flag value is non-zero. If the value is 1 (Probe trigger),
 *          2 (GEDR trigger), or 3 (both), the function returns true indicating a valid
 *          event trigger has been received. If the value is 0, the function returns false,
 *          indicating no trigger condition. No state is modified by this function; it is
 *          a pure predicate used by HandleAdasAcoreTriggerEvt to gate downstream trigger
 *          processing. Execution is fully bounded and deterministic with O(1) complexity.
 * @param[in] flag Data upload request flag value received from ZAT trigger data.
 *                 Valid range: [0, 255]. Values: 0=no trigger, 1=Probe, 2=GEDR, 3=both.
 * @return True if the flag is non-zero (valid trigger), false otherwise.
 * @retval true  Upload request flag is non-zero — valid trigger present.
 * @retval false Upload request flag is zero — no valid trigger.
 * @throws None
 * @pre None.
 * @post No state change. Pure predicate function.
 * @note Called by: ProbeComm internally during trigger processing.
 * @warning Any non-zero value evaluates as true; the calling function
 *          HandleAdasAcoreTriggerEvt is responsible for further routing based on
 *          specific flag values (Probe-only vs GEDR-only vs both).
 * @see HandleAdasAcoreTriggerEvt
 * @requirements SWR-REQ-03-02-002;SWR-REQ-03-003
 * @rationale Zero flag indicates no upload request; non-zero indicates valid trigger.
 *           This is the intended safe default since the flag is treated as a presence indicator.
 */
bool ProbeComm::ValidateTriggerUploadRequestFlag(const uint8_t flag) const noexcept
{
    /* Step 1: Receive input flag of type uint8_t */
    /* Step 2: Evaluate flag value */
    if (flag != static_cast<uint8_t>(0U))
    {
        /* Step 3: Non-zero value means a valid trigger is present (Probe=1, GEDR=2, Both=3) */
        return true;
    }
    else
    {
        /* Step 4: Zero means no active trigger; suppress downstream processing */
        return false;
    }
}

/**
 * @brief Validates whether the acceptance counter for a category has reached the configurable limit.
 * @details Looks up the category in categoryTriggerCountMap_ and compares against
 *          sameCategoryLimitPerDC_. If the categoryId is not found in the map, the count
 *          is treated as zero, meaning the trigger is below the limit and the function
 *          returns true (acceptance allowed). If the categoryId is found and the stored
 *          count is greater than or equal to sameCategoryLimitPerDC_, the function returns
 *          false (limit reached, rejection required). The function does not modify
 *          categoryTriggerCountMap_; counter increment upon acceptance is handled by the
 *          calling context. Execution is deterministic and O(log n) bounded by the map lookup.
 * @param[in] categoryId Category identifier to check. Valid range: [0, UINT32_MAX].
 * @return True if the category limit has NOT been reached (acceptance allowed),
 *         false if limit reached (rejection required).
 * @retval true  Category acceptance count is below the limit — trigger may be accepted.
 * @retval false Category acceptance count has reached or exceeded the limit — trigger must be rejected.
 * @throws None
 * @pre categoryTriggerCountMap_ is initialized (may be empty for new driving cycle).
 * @post No state change. Read-only operation on categoryTriggerCountMap_.
 * @note Called by: ProbeComm internally during trigger validation.
 * @warning If sameCategoryLimitPerDC_ is zero due to configuration error, this function
 *          returns false for all categories, effectively rejecting all triggers. This
 *          condition must be detected at configuration validation during initialization.
 * @see ResetCategoryCounterOnNewDriveCycle, HandleAdasAcoreTriggerEvt
 * @requirements SWR-REQ-03-12-001;SWR-REQ-03-12-002;SWR-REQ-03-12-005;SWR-REQ-03-12-006
 * @rationale Per-category limits prevent excessive data collection for a single category
 *           per drive cycle, ensuring fair resource distribution across event categories.
 */
bool ProbeComm::CheckSameCategoryLimit(const uint32_t categoryId) const noexcept
{
    /* Step 1: Receive categoryId : uint32_t */

    /* Step 2: Attempt lookup of categoryId in categoryTriggerCountMap_ */
    uint32_t currentCount = 0U;

    const auto it = categoryTriggerCountMap_.find(categoryId);
    if (it != categoryTriggerCountMap_.end())
    {
        currentCount = it->second;
    }
    else
    {
        /* Step 3: Category not seen in this driving cycle; count starts at zero */
        currentCount = 0U;
    }

    /* Step 4: Compare count against configurable limit.
     * Return semantics per header: true = below limit (acceptance allowed),
     * false = limit reached (rejection required).
     * Pseudocode returns true when limit reached, but header says:
     *   @retval true  Category acceptance count is below the limit.
     *   @retval false Category acceptance count has reached or exceeded the limit.
     * We follow the header contract. */
    if (currentCount >= sameCategoryLimitPerDC_)
    {
        /* Limit reached or exceeded: trigger must be rejected */
        return false;
    }
    else
    {
        /* Below limit: trigger may be accepted */
        return true;
    }
}

/**
 * @brief Validates whether the active event process count exceeds the allowed overlap limit.
 * @details Reads activeEventProcessCount_ and allowedOverlapTriggerNum_ from the ProbeComm
 *          instance's private members. If activeEventProcessCount_ is greater than or equal
 *          to allowedOverlapTriggerNum_, the function returns false, indicating that no
 *          additional parallel event processing can be initiated. If activeEventProcessCount_
 *          is strictly less than allowedOverlapTriggerNum_, the function returns true,
 *          indicating that a new parallel event data generation process may begin. The
 *          function does not modify activeEventProcessCount_; incrementing and decrementing
 *          this counter is managed by the trigger acceptance and event completion paths.
 *          Execution is deterministic, O(1), and fully bounded.
 * @return True if overlap limit has NOT been exceeded (new trigger allowed), false otherwise.
 * @retval true  Active event count is below the overlap limit — trigger may be accepted.
 * @retval false Active event count has reached or exceeded the overlap limit — trigger must be rejected.
 * @throws None
 * @pre None.
 * @post No state change. Read-only comparison of private members.
 * @note Called by: ProbeComm internally during trigger validation.
 * @warning If allowedOverlapTriggerNum_ is zero due to configuration error, this function
 *          always returns false, blocking all event trigger acceptance. This condition must
 *          be detected and corrected at initialization during configuration validation.
 * @see HandleAdasAcoreTriggerEvt, SendAllowedOverlapCountToZAT
 * @requirements SWR-REQ-03-04-003;SWR-REQ-03-04-004
 * @rationale Overlap limit prevents resource exhaustion from too many concurrent events.
 *           Bounded comparison ensures deterministic execution in the event callback context.
 */
bool ProbeComm::CheckOverlapTriggerLimit() const noexcept
{
    /* Step 1: Read current values of activeEventProcessCount_ and allowedOverlapTriggerNum_ */

    /* Step 2: Compare active count against allowed overlap limit.
     * Return semantics per header: true = below limit (allowed), false = at/above limit (reject).
     * Pseudocode returns true when limit reached, but header says:
     *   @retval true  Active event count is below the overlap limit.
     *   @retval false Active event count has reached or exceeded the overlap limit.
     * We follow the header contract. */
    if (activeEventProcessCount_ >= allowedOverlapTriggerNum_)
    {
        /* Step 3: Overlap limit reached; incoming trigger must be rejected */
        return false;
    }
    else
    {
        /* Step 4: Capacity available; trigger may be accepted */
        return true;
    }
}

/**
 * @brief Clamps log data start time to the negative of past data retention setting when exceeded.
 * @details Accepts the raw log data start time (a negative offset in seconds from trigger
 *          point) and the configured past data retention limit. Computes the absolute value
 *          of startTime and checks whether it exceeds the retention limit cast to int32_t.
 *          If the absolute start time is greater than the retention limit, the effective
 *          start time is clamped to the negative of the retention limit value. Otherwise,
 *          the start time is accepted unchanged. The result is stored in the private member
 *          effectiveLogStartTime_ and also returned to the caller. This ensures the log
 *          data window never reaches beyond available buffer history, preventing access
 *          violations and undefined data states. The function is deterministic, performs
 *          no dynamic allocation, and executes within a single bounded evaluation.
 * @param[in] startTime Log data start time in seconds. Valid range: [INT32_MIN, 0].
 *                      Represents a negative offset from the trigger point.
 * @param[in] retentionLimit Past data retention limit in seconds. Valid range: [0, UINT32_MAX].
 *                           Defines the maximum allowable depth of past data.
 * @return Clamped start time value stored in effectiveLogStartTime_.
 * @retval Clamped value (-retentionLimit) if absolute startTime exceeds retention limit.
 * @retval Original startTime if within retention limit.
 * @throws None
 * @pre None.
 * @post effectiveLogStartTime_ is updated with the clamped or original start time value.
 * @note Called by: ProbeComm internally during trigger processing.
 * @warning If retentionLimit is zero, the effective start time will be clamped to zero
 *          regardless of input, which is a safe and deterministic default.
 * @see ValidateLogEndTimeClamping, HandleAdasAcoreTriggerEvt
 * @requirements SWR-REQ-03-02-003;SWR-REQ-03-17-007
 * @rationale Clamping prevents requesting data beyond the available retention window,
 *           avoiding access violations and undefined data states in the log buffer.
 */
int32_t ProbeComm::ValidateLogStartTimeClamping(const int32_t startTime,
                                                 const uint32_t retentionLimit) const noexcept
{
    /* Step 1: Compute the absolute value of the incoming start time.
     * Use manual absolute value computation to avoid undefined behavior
     * with std::abs on INT32_MIN in some implementations. */
    const int32_t absStartTime = (startTime < static_cast<int32_t>(0))
                                     ? static_cast<int32_t>(-startTime)
                                     : startTime;

    /* Step 2: Cast retentionLimit to int32_t for signed arithmetic comparison.
     * Clamp retentionLimit to INT32_MAX to prevent overflow during cast. */
    const int32_t retentionLimitSigned =
        (retentionLimit > static_cast<uint32_t>(INT32_MAX))
            ? INT32_MAX
            : static_cast<int32_t>(retentionLimit);

    /* Step 3: Compare absolute start time with the past data retention limit */
    int32_t result = 0;
    if (absStartTime > retentionLimitSigned)
    {
        /* Step 3a: Clamp to negative retention limit */
        result = static_cast<int32_t>(-retentionLimitSigned);
    }
    else
    {
        /* Step 3b: Accept the received start time as-is */
        result = startTime;
    }

    /* Note: effectiveLogStartTime_ is mutable state; however this function is const.
     * The result is returned to the caller who is responsible for storing it.
     * The pseudocode assigns to effectiveLogStartTime_ but the header declares
     * this function as const noexcept, so we return the value for the caller to store. */

    /* Step 4: Return the validated effective start time */
    return result;
}

