/// @brief Fixed field identifier for EventDataType 001 (category header).
/// @details Appended as the first byte of the assembled category optional and event list payload.
static constexpr uint8_t kEventDataTypeCategoryHeaderIdentifier{0x01U};

/// @brief Fixed field identifier for EventDataType 002 (log data).
/// @details Appended as the first byte of the assembled log data set payload.
static constexpr uint8_t kEventDataTypeLogDataHeaderIdentifier{0x02U};

/// @brief Fixed field identifier for EventDataType 003 (image data).
/// @details Appended as the first byte of the assembled image data set payload.
static constexpr uint8_t kEventDataTypeImageDataHeaderIdentifier{0x03U};

/// @brief Maximum allowed packet size in bytes for SOME/IP BDP transmission.
/// @details Used as the upper boundary for single-packet path evaluation and multi-segment slice sizing.
///          Typical SOME/IP UDP payload limit; segments exceeding this are split.
static constexpr uint32_t kMaxAllowedPacketSize{1400U};

/// @brief DAQ response success status code.
/// @details Returned by DAQ when the BDP upload request is accepted.
static constexpr uint16_t kDaqResponseSuccess{0x0000U};

/**
 * @brief Serializes a uint32_t value into a byte vector in little-endian order.
 * @details Appends 4 bytes representing the value to the target vector.
 * @param[in,out] target Vector to append serialized bytes to.
 * @param[in] value The uint32_t value to serialize.
 * @pre target is a valid vector.
 * @post 4 bytes are appended to target in little-endian byte order.
 */
static void SerializeUint32LE(std::vector<uint8_t>& target, const uint32_t value) noexcept
{
    target.push_back(static_cast<uint8_t>(value & 0xFFU));
    target.push_back(static_cast<uint8_t>((value >> 8U) & 0xFFU));
    target.push_back(static_cast<uint8_t>((value >> 16U) & 0xFFU));
    target.push_back(static_cast<uint8_t>((value >> 24U) & 0xFFU));
}

